Object.assign(I18N.hi, {"नोंदणी फी जमा केल्यानंतरच आपल्याला ओळखपत्र, लेस इत्यादी साहित्य दिले जाईल.": "पंजीकरण शुल्क जमा करने के बाद ही आपको पहचान-पत्र, लेस आदि सामग्री दी जाएगी।"});
Object.assign(I18N.en, {"नोंदणी फी जमा केल्यानंतरच आपल्याला ओळखपत्र, लेस इत्यादी साहित्य दिले जाईल.": "Your ID card, lace, etc. will be given only after the registration fee is paid."});
window.__lang = 'mr';
const _oT = new WeakMap(), _oP = new WeakMap();
const _DEV='०१२३४५६७८९';
function d2l(s){ return String(s).replace(/[०-९]/g, c => '0123456789'[_DEV.indexOf(c)]); }
function tr(s){
  if(window.__lang==='mr' || s==null) return s;
  const d = I18N[window.__lang]; if(!d) return s;
  const k = String(s).trim();
  return d2l((k in d) ? String(s).replace(k, d[k]) : s);
}
function applyLang(lang){
  window.__lang = lang;
  const d = I18N[lang], skip = {SCRIPT:1,STYLE:1,NOSCRIPT:1};
  const w = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, { acceptNode(n){
    const p = n.parentNode;
    if(!p || skip[p.nodeName]) return NodeFilter.FILTER_REJECT;
    if(p.closest && p.closest('[data-set-lang]')) return NodeFilter.FILTER_REJECT;
    return n.nodeValue.trim() ? NodeFilter.FILTER_ACCEPT : NodeFilter.FILTER_REJECT;
  }});
  let n;
  while(n = w.nextNode()){
    if(!_oT.has(n)) _oT.set(n, n.nodeValue);
    const orig = _oT.get(n), k = orig.trim();
    let _v = (lang==='mr' || !d || !(k in d)) ? orig : orig.replace(k, d[k]);
    if(lang!=='mr') _v = d2l(_v);
    n.nodeValue = _v;
  }
  document.querySelectorAll('[placeholder]').forEach(el=>{
    if(!_oP.has(el)) _oP.set(el, el.getAttribute('placeholder'));
    const orig = _oP.get(el), k = orig.trim();
    let _pv = (lang==='mr' || !d || !(k in d)) ? orig : d[k];
    if(lang!=='mr') _pv = d2l(_pv);
    el.setAttribute('placeholder', _pv);
  });
  document.documentElement.setAttribute('lang', lang);
  document.querySelectorAll('[data-set-lang]').forEach(b=> b.classList.toggle('active', b.getAttribute('data-set-lang')===lang));
}
function setLang(lang){ applyLang(lang); }
document.querySelectorAll('[data-set-lang]').forEach(b=>{
  b.addEventListener('click',()=>setLang(b.getAttribute('data-set-lang')));
});
setLang('en');

