/* ================= COUNTDOWN ================= */
const enToDev = n => String(n).replace(/\d/g, d => "०१२३४५६७८९"[d]);
const num = n => (window.__lang && window.__lang!=='mr') ? String(n) : enToDev(n);
const pad = n => String(n).padStart(2,'0');
const target = new Date(CONFIG.eventStart).getTime();
function tick(){
  const now = Date.now();
  let diff = Math.max(0, target - now);
  const d = Math.floor(diff/86400000); diff -= d*86400000;
  const h = Math.floor(diff/3600000);  diff -= h*3600000;
  const m = Math.floor(diff/60000);    diff -= m*60000;
  const s = Math.floor(diff/1000);
  document.getElementById('cd-d').textContent = num(pad(d));
  document.getElementById('cd-h').textContent = num(pad(h));
  document.getElementById('cd-m').textContent = num(pad(m));
  document.getElementById('cd-s').textContent = num(pad(s));
}
tick(); setInterval(tick,1000);

