const galGrid = document.getElementById('galleryGrid');
const galleryCount = document.getElementById('galleryCount');
if(galleryCount) galleryCount.textContent = tr(enToDev(GALLERY.length) + ' क्षणचित्रे');
GALLERY.forEach((src,i)=>{
  const d=document.createElement('div');
  d.className='gal-item'; d.tabIndex=0; d.setAttribute('role','button');
  d.setAttribute('aria-label','क्षणचित्र '+enToDev(i+1)+' मोठे पाहा');
  d.innerHTML=`<img src="${src}" loading="lazy" alt="मागील पारायण सोहळा — क्षणचित्र ${enToDev(i+1)}" />`;
  d.addEventListener('click',()=>openLightbox(i));
  d.addEventListener('keydown',e=>{ if(e.key==='Enter'||e.key===' '){ e.preventDefault(); openLightbox(i);} });
  if(i>=8) d.classList.add('gal-hidden');
  galGrid.appendChild(d);
});
(function(){
  const btn=document.getElementById('galToggle');
  if(!btn) return;
  const extra=Array.from(galGrid.querySelectorAll('.gal-hidden'));
  if(extra.length===0){ btn.parentElement.style.display='none'; return; }
  let open=false;
  const label=()=> btn.textContent = tr(open ? 'कमी दाखवा' : ('सर्व '+enToDev(GALLERY.length)+' छायाचित्रे पाहा  ↓'));
  label();
  btn.addEventListener('click',()=>{ open=!open; extra.forEach(el=>el.classList.toggle('gal-hidden',!open)); label(); });
})();

/* ================= LIGHTBOX ================= */
let lbIndex=0;
const lb=document.getElementById('lightbox');
function renderLb(){
  document.getElementById('lbImg').src=GALLERY[lbIndex];
  document.getElementById('lbCount').textContent=enToDev(lbIndex+1)+' / '+enToDev(GALLERY.length);
}
function openLightbox(i){ lbIndex=i; renderLb(); lb.classList.add('open'); lb.setAttribute('aria-hidden','false'); document.body.style.overflow='hidden'; }
function closeLightbox(){ lb.classList.remove('open'); lb.setAttribute('aria-hidden','true'); document.body.style.overflow=''; }
function lbStep(dir){ lbIndex=(lbIndex+dir+GALLERY.length)%GALLERY.length; renderLb(); }
lb.addEventListener('click',e=>{
  if(e.target.closest('[data-lb-prev]')) return lbStep(-1);
  if(e.target.closest('[data-lb-next]')) return lbStep(1);
  if(e.target.closest('.lb-close')) return closeLightbox();
  if(e.target.id==='lbImg') return;
  closeLightbox();
});
document.addEventListener('keydown',e=>{
  if(!lb.classList.contains('open')) return;
  if(e.key==='Escape') closeLightbox();
  else if(e.key==='ArrowRight') lbStep(1);
  else if(e.key==='ArrowLeft') lbStep(-1);
});
let lbTsx=0;
lb.addEventListener('touchstart',e=>{ lbTsx=e.changedTouches[0].clientX; },{passive:true});
lb.addEventListener('touchend',e=>{ const dx=e.changedTouches[0].clientX-lbTsx; if(Math.abs(dx)>50) lbStep(dx<0?1:-1); });

/* ================= REVEAL ON SCROLL ================= */
const io = new IntersectionObserver(entries=>{
  entries.forEach(en=>{ if(en.isIntersecting){ en.target.style.opacity=1; en.target.style.transform='none'; io.unobserve(en.target);} });
},{threshold:.08});
document.querySelectorAll('.card,.imp-item,.rule,.centre-card,.stat,.ledger-row,.sankalp-note').forEach(el=>{
  if(matchMedia('(prefers-reduced-motion: reduce)').matches) return;
  el.style.opacity=0; el.style.transform='translateY(16px)'; el.style.transition='opacity .5s ease, transform .5s ease';
  io.observe(el);
});

/* ===================== REGISTER POPUP ===================== */
(function(){
  const pop = document.getElementById('regPop');
  if(!pop) return;
  const openPop  = ()=> pop.classList.add('open');
  const closePop = ()=> pop.classList.remove('open');
  let seen=false; try{ seen = sessionStorage.getItem('regPopSeen')==='1'; }catch(e){}
  if(!seen){ setTimeout(()=>{ openPop(); try{ sessionStorage.setItem('regPopSeen','1'); }catch(e){} }, 1500); }
  document.getElementById('regPopClose').addEventListener('click', closePop);
  document.getElementById('regPopCta').addEventListener('click', closePop);
  pop.addEventListener('click', e=>{ if(e.target===pop) closePop(); });
  document.addEventListener('keydown', e=>{ if(e.key==='Escape') closePop(); });
})();
